import{_ as t,o as r,c as o,ag as i}from"./chunks/framework.DUvHsH_U.js";const d=JSON.parse('{"title":"Sign-Up Territory Setup Guide","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/sign-up-territory-setup.md","filePath":"getting-started/sign-up-territory-setup.md","lastUpdated":1777975835000}'),s={name:"getting-started/sign-up-territory-setup.md"};function n(a,e,l,h,c,p){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="sign-up-territory-setup-guide" tabindex="-1">Sign-Up Territory Setup Guide <a class="header-anchor" href="#sign-up-territory-setup-guide" aria-label="Permalink to &quot;Sign-Up Territory Setup Guide&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This guide ensures that new users can browse and select their city and area during the mobile app&#39;s sign-up process. Without these steps, the location dropdowns will appear empty or block registration entirely.</p><hr><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><h3 id="_1-grant-guest-users-access-to-territories" tabindex="-1">1. Grant Guest Users Access to Territories <a class="header-anchor" href="#_1-grant-guest-users-access-to-territories" aria-label="Permalink to &quot;1. Grant Guest Users Access to Territories&quot;">​</a></h3><p>The mobile app shows city and area lists to users who have not yet logged in. You must allow unregistered visitors to view the Territory records.</p><ol><li>Log in to ERPNext as an Administrator.</li><li>Open the <strong>Role Permissions Manager</strong> (search for it in the awesome bar).</li><li>In the list, find the row for the <strong>Territory</strong> document type.</li><li>Click into that row to open the permission table.</li><li>Add or edit the row for the <strong>Guest</strong> role.</li><li>Check only the <strong>Read</strong> permission checkbox. Leave all other permissions unchecked.</li><li>Click <strong>Save</strong>.</li></ol><blockquote><p><strong>Why this matters:</strong> If Guest does not have Read access on Territory, the city and area dropdowns on the sign-up screen will load as blank lists, and the user will be unable to complete registration.</p></blockquote><hr><h3 id="_2-mark-which-territories-are-active-for-the-mobile-app" tabindex="-1">2. Mark Which Territories Are Active for the Mobile App <a class="header-anchor" href="#_2-mark-which-territories-are-active-for-the-mobile-app" aria-label="Permalink to &quot;2. Mark Which Territories Are Active for the Mobile App&quot;">​</a></h3><p>Not every territory in the ERPNext database should be selectable by a new mobile user. Each territory record has a flag that controls mobile visibility.</p><ol><li>Go to the <strong>Territory List</strong> (Selling &gt; Territory &gt; Territory List).</li><li>Open the city or area record you want to activate.</li><li>In the territory form, scroll to the section that contains the <strong>Covered in Mobile App</strong> checkbox.</li><li>Check the box.</li><li>Click <strong>Save</strong>.</li></ol><p><strong>Group vs. Non-Group territories:</strong></p><ul><li><strong>Cities</strong> are the top-level <strong>Group</strong> territories (the &quot;Is Group&quot; checkbox is checked). These appear in the first dropdown labeled <strong>City</strong>.</li><li><strong>Areas</strong> are the child <strong>Non-Group</strong> territories (the &quot;Is Group&quot; checkbox is unchecked). These appear in the second dropdown labeled <strong>Territory</strong> after a city is chosen.</li></ul><hr><h3 id="_3-confirm-the-custom-backend-application-is-installed" tabindex="-1">3. Confirm the Custom Backend Application Is Installed <a class="header-anchor" href="#_3-confirm-the-custom-backend-application-is-installed" aria-label="Permalink to &quot;3. Confirm the Custom Backend Application Is Installed&quot;">​</a></h3><p>The sign-up flow relies on backend logic that is not part of standard ERPNext. This logic is delivered through a custom ERPNext application.</p><ol><li>From the ERPNext desk, open <strong>Installed Applications</strong> (search the awesome bar).</li><li>Look through the list for the company&#39;s custom app name.</li><li>If the custom app is <strong>not listed</strong>, it must be installed on the client&#39;s site before sign-up will work.</li></ol><blockquote><p>If the app is listed but you still see errors, contact the development team. Do not attempt to modify server code or install bench apps yourself.</p></blockquote><hr><h2 id="after-sign-up-activating-the-new-user" tabindex="-1">After Sign-Up: Activating the New User <a class="header-anchor" href="#after-sign-up-activating-the-new-user" aria-label="Permalink to &quot;After Sign-Up: Activating the New User&quot;">​</a></h2><p>When a user successfully completes sign-up in the mobile app, a new <strong>User</strong> record is automatically created in ERPNext. However, this alone does not allow the user to log in.</p><h3 id="what-the-user-will-see" tabindex="-1">What the user will see <a class="header-anchor" href="#what-the-user-will-see" aria-label="Permalink to &quot;What the user will see&quot;">​</a></h3><p>If the user tries to log in immediately after signing up, the app will display a message saying the account is <strong>not activated yet</strong>.</p><h3 id="how-to-activate-the-user" tabindex="-1">How to activate the user <a class="header-anchor" href="#how-to-activate-the-user" aria-label="Permalink to &quot;How to activate the user&quot;">​</a></h3><p>The user must be linked to a <strong>Customer</strong> record before they can log in. You can do this in two ways:</p><p><strong>Option A: Connect from the Customer document</strong></p><ol><li>Go to the <strong>Customer List</strong> and open the relevant customer record.</li><li>Scroll to the <strong>Portal Users</strong> section.</li><li>Click <strong>Add Row</strong>.</li><li>Select the newly created user.</li><li>Click <strong>Save</strong>.</li></ol><p><strong>Option B: Connect from the Shopping Cart Orders page</strong></p><ol><li>Open the <strong>Shopping Cart Orders</strong> page in ERPNext.</li><li>Find the pending order from the new user.</li><li>Use the page controls to link the user to the customer record.</li></ol><blockquote><p>For more details on login-related setup and troubleshooting, see the <strong>Login Setup</strong> guide (<code>02-login-setup.md</code>).</p></blockquote><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>If the City or Territory dropdown shows an error message</strong></p><ul><li>The <strong>Guest</strong> role does not have <strong>Read</strong> permission on the <strong>Territory</strong> document (see Step 1).</li><li>Return to the Role Permissions Manager, find the Territory row, and make sure Guest has Read access checked.</li></ul><hr><p><strong>If the City or Territory dropdown opens but shows an empty list</strong></p><ul><li>There are no Territory records created in ERPNext, or they are not configured correctly.</li><li>For the <strong>City</strong> dropdown, ensure there are Territory records with <strong>Is Group</strong> checked.</li><li>For the <strong>Territory</strong> dropdown, ensure the child records have the correct <strong>Parent Territory</strong> link to the selected city.</li></ul><hr><p><strong>If the user selects an area and the app immediately blocks the selection with a message saying the service is not available in that region</strong></p><ul><li>The <strong>Covered in Mobile App</strong> checkbox on that specific territory record is unchecked (see Step 2).</li><li>Open the Territory document in ERPNext, check the box, and save.</li></ul><hr><p><strong>If the app throws an error that says &quot;couldn&#39;t find module profile customer&quot;</strong></p><ul><li>The company&#39;s <strong>custom ERPNext application is either missing or misconfigured</strong> on the server (see Step 3).</li><li>Verify the custom app is listed under <strong>Installed Applications</strong>.</li><li>If it is missing, the site was not provisioned with the correct backend package. Escalate to the development or DevOps team to reinstall the custom app on that client&#39;s site.</li></ul>',45)])])}const g=t(s,[["render",n]]);export{d as __pageData,g as default};
